/*
 * Linear Congruential Generator (LCG) - C Implementation
 * Demonstrates the formula: X(n+1) = (a * X(n) + c) mod m
 * 
 * Note: LCGs are NOT cryptographically secure!
 * This code is for educational purposes only.
 */

#include <stdio.h>
#include <stdlib.h>
#include <stdint.h>

/* Define LCG structure */
typedef struct {
 uint64_t a; /* Multiplier */
 uint64_t c; /* Increment */
 uint64_t m; /* Modulus */
 uint64_t state; /* Current state (seed) */
} LCG;

/* Initialize LCG with parameters */
void lcg_init(LCG *lcg, uint64_t a, uint64_t c, uint64_t m, uint64_t seed) {
 lcg->a = a;
 lcg->c = c;
 lcg->m = m;
 lcg->state = seed % m; /* Ensure seed is valid */
}

/* Generate next random number */
uint64_t lcg_next(LCG *lcg) {
 /* Core LCG formula: X(n+1) = (a * X(n) + c) mod m */
 lcg->state = (lcg->a * lcg->state + lcg->c) % lcg->m;
 return lcg->state;
}

/* Generate random float in range [0, 1) */
double lcg_next_float(LCG *lcg) {
 return (double)lcg_next(lcg) / (double)lcg->m;
}

/* Compute GCD using Euclidean algorithm */
uint64_t gcd(uint64_t a, uint64_t b) {
 while (b != 0) {
 uint64_t temp = b;
 b = a % b;
 a = temp;
 }
 return a;
}

/* Check if parameters satisfy full period conditions (Hull-Dobell) */
int check_full_period(uint64_t a, uint64_t c, uint64_t m) {
 int valid = 1;

 /* Condition 1: gcd(c, m) = 1 */
 if (gcd(c, m) != 1) {
 printf("FAIL: c and m must be coprime (gcd=%lu)\n", gcd(c, m));
 valid = 0;
 }

 /* Condition 2: (a-1) divisible by all prime factors of m */
 /* Simple check for common prime factors */
 uint64_t temp_m = m;
 for (uint64_t p = 2; p * p <= temp_m; p++) {
 if (temp_m % p == 0) {
 if ((a - 1) % p != 0) {
 printf("FAIL: (a-1) must be divisible by %lu\n", p);
 valid = 0;
 }
 while (temp_m % p == 0) temp_m /= p;
 }
 }
 if (temp_m > 1) {
 if ((a - 1) % temp_m != 0) {
 printf("FAIL: (a-1) must be divisible by %lu\n", temp_m);
 valid = 0;
 }
 }

 /* Condition 3: If m multiple of 4, (a-1) must be multiple of 4 */
 if (m % 4 == 0 && (a - 1) % 4 != 0) {
 printf("FAIL: (a-1) must be multiple of 4\n");
 valid = 0;
 }

 return valid;
}

/* Detect period of LCG */
uint64_t detect_period(LCG *lcg, uint64_t max_checks) {
 /* Use array to track seen states - only works for reasonable m */
 if (lcg->m > 1000000) {
 printf("Period too large to detect with this method\n");
 return 0;
 }

 uint64_t *seen = calloc(lcg->m, sizeof(uint64_t));
 if (!seen) return 0;

 uint64_t initial_state = lcg->state;
 uint64_t period = 0;

 for (uint64_t i = 0; i < max_checks; i++) {
 uint64_t current = lcg->state;

 if (seen[current] != 0) {
 period = i - seen[current] + 1;
 break;
 }
 seen[current] = i + 1;
 lcg_next(lcg);
 }

 lcg->state = initial_state;
 free(seen);
 return period;
}

/* Demonstrate bad LCG from textbook */
void demo_bad_lcg(void) {
 printf("============================================================\n");
 printf("EXAMPLE 1: Bad LCG (Short Period from textbook)\n");
 printf("Parameters: m=9, a=2, c=5, seed=1\n");
 printf("============================================================\n");

 LCG lcg;
 lcg_init(&lcg, 2, 5, 9, 1);

 printf("Sequence: ");
 for (int i = 0; i < 10; i++) {
 printf("%lu ", lcg_next(&lcg));
 }
 printf("\n");

 /* Reset and detect period */
 lcg_init(&lcg, 2, 5, 9, 1);
 uint64_t period = detect_period(&lcg, 100);
 printf("Detected period: %lu (should be 2)\n", period);
}

/* Demonstrate MINSTD (Park & Miller) */
void demo_minstd(void) {
 printf("\n============================================================\n");
 printf("EXAMPLE 2: MINSTD (Park & Miller)\n");
 printf("Parameters: m=2^31-1, a=16807, c=0, seed=123456789\n");
 printf("============================================================\n");

 /* MINSTD parameters */
 uint64_t m = 2147483647; /* 2^31 - 1 (prime) */
 uint64_t a = 16807;
 uint64_t c = 0;
 uint64_t seed = 123456789;

 printf("Checking full period conditions: ");
 int valid = check_full_period(a, c, m);
 printf("%s\n", valid ? "PASSED" : "FAILED");

 LCG lcg;
 lcg_init(&lcg, a, c, m, seed);

 printf("\nFirst 10 values:\n");
 for (int i = 0; i < 10; i++) {
 uint64_t val = lcg_next(&lcg);
 printf(" X%d = %lu (normalized: %.10f)\n", 
 i, val, (double)val / (double)m);
 }
}

/* Demonstrate older C library (glibc) parameters */
void demo_glibc(void) {
 printf("\n============================================================\n");
 printf("EXAMPLE 3: Older glibc parameters\n");
 printf("Parameters: m=2^31, a=1103515245, c=12345\n");
 printf("============================================================\n");

 /* These were used in older C library implementations */
 uint64_t m = 2147483648ULL; /* 2^31 */
 uint64_t a = 1103515245ULL;
 uint64_t c = 12345;

 LCG lcg;
 lcg_init(&lcg, a, c, m, 1);

 printf("First 10 values:\n");
 for (int i = 0; i < 10; i++) {
 printf(" %lu\n", lcg_next(&lcg));
 }

 printf("\nWARNING: LCGs are cryptographically INSECURE!\n");
 printf("Never use for keys, nonces, or security-critical values.\n");
}

int main(void) {
 demo_bad_lcg();
 demo_minstd();
 demo_glibc();

 return 0;
}
